module convolutional_encoder(
    input wire clk,
    input wire rst,
    input wire data_in,
    output reg [1:0] data_out
);
    reg delayed_input;
    reg input_delay_delay;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            delayed_input <= 0;
            input_delay_delay <= 0;
            data_out <= 2'b00;
        end else begin
            data_out[0] <= data_in ^ delayed_input; // Output 1
            data_out[1] <= data_in ^ delayed_input ^ input_delay_delay; // Output 2

            // Update delays
            input_delay_delay <= delayed_input;
            delayed_input <= data_in;
        end
    end
endmodule
